-- Another session can set different level
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;

BEGIN TRANSACTION;
SELECT * FROM Accounts;

BEGIN TRY
 BEGIN TRANSACTION;

 UPDATE Accounts
 SET balance = balance - 5000
 WHERE account_id = 'ACC001';

 IF (SELECT balance FROM Accounts WHERE account_id = 'ACC001') < 0
 BEGIN
 RAISERROR('Insufficient funds', 16, 1);
 ROLLBACK;
 RETURN;
 END

 UPDATE Accounts
 SET balance = balance + 5000
 WHERE account_id = 'ACC002';

 COMMIT;
 PRINT 'Transfer completed successfully';

END TRY
BEGIN CATCH
 ROLLBACK;
 PRINT 'Error: ' + ERROR_MESSAGE();
END CATCH
